import { Request, Response, NextFunction } from 'express';
import { ZodError } from 'zod';
import { logger } from '../utils/logger';

export function errorHandler(
  err: unknown,
  req: Request,
  res: Response,
  next: NextFunction
): void {
  const requestId = req.headers['x-request-id'] || 'unknown';

  if (err instanceof ZodError) {
    logger.error(`Validation error [RequestId: ${requestId}]: ${JSON.stringify(err.errors)}`);
    res.status(400).json({
      success: false,
      errors: err.errors,
    });
  } else if (err instanceof Error) {
    logger.error(`Unhandled error [RequestId: ${requestId}]: ${err.message}`, { stack: err.stack });
    res.status(500).json({
      success: false,
      message: 'Internal Server Error',
    });
  } else {
    logger.error(`Unknown error [RequestId: ${requestId}]`, { error: err });
    res.status(500).json({
      success: false,
      message: 'Internal Server Error',
    });
  }
}

export interface BaseDTO<T> {
  toDTO(): T;
}

export interface Mapper<DomainModel, DTO> {
  toDomain(dto: DTO): DomainModel;
  toDTO(entity: DomainModel): DTO;
}

import { createLogger, format, transports } from 'winston';

export const logger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
    format.errors({ stack: true }),
    format.splat(),
    format.json()
  ),
  transports: [
    new transports.Console(),
    new transports.File({ filename: 'error.log', level: 'error' }),
    new transports.File({ filename: 'combined.log' }),
  ],
});
